const T = {
  bg:        '#0e0e0e',
  bgCard:    '#1A1A1A',
  bgRaised:  '#1e1e1e',
  border:    'rgba(255,255,255,0.07)',
  borderHi:  'rgba(255,255,255,0.16)',
  accent:    '#F76803',
  accentDim: 'rgba(247,104,3,0.12)',
}

// ── Sub-components ────────────────────────────────────────────────────────────

function BentoCard({
  children,
  colSpan,
  accent,
  highlight,
  glass,
}: {
  children: React.ReactNode
  colSpan?: string
  accent?: boolean
  highlight?: boolean
  glass?: boolean
}) {
  const [hovered, setHovered] = React.useState(false)

  const base: React.CSSProperties = {
    gridColumn: colSpan ? `span ${colSpan}` : undefined,
    gridRow: 'span 2',
    position: 'relative',
    borderRadius: 18,
    padding: 'var(--xxl)',
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'space-between',
    cursor: 'default',
    transition: 'transform 300ms cubic-bezier(0.16,1,0.3,1), border-color 300ms, box-shadow 300ms',
  }

  const variantStyle: React.CSSProperties = highlight
    ? {
        background: 'linear-gradient(145deg, #F76803, #C55302)',
        border: `1px solid #FC7D21`,
      }
    : accent
    ? {
        background: 'linear-gradient(145deg, #1a0e06, #1e1208)',
        border: `1px solid rgba(247,104,3,${hovered ? 0.45 : 0.2})`,
      }
    : glass
    ? {
        background: 'rgba(255,255,255,0.04)',
        backdropFilter: 'blur(8px)',
        border: `1px solid ${hovered ? T.borderHi : T.border}`,
      }
    : {
        background: T.bgCard,
        border: `1px solid ${hovered ? T.borderHi : T.border}`,
      }

  const hoverStyle: React.CSSProperties = hovered
    ? {
        transform: 'translateY(-5px)',
        boxShadow: `0 16px 40px rgba(0,0,0,0.45), inset 0 1px 0 rgba(255,255,255,0.10)`,
      }
    : {}

  return (
    <div
      style={{ ...base, ...variantStyle, ...hoverStyle }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      {accent && (
        <div style={{
          position: 'absolute', inset: -1, borderRadius: 18, pointerEvents: 'none',
          background: 'radial-gradient(ellipse at 30% 0%, rgba(247,104,3,0.12) 0%, transparent 60%)',
        }} />
      )}
      {children}
    </div>
  )
}

function CardEyebrow({ children, light }: { children: React.ReactNode; light?: boolean }) {
  return (
    <Typography
      variant="caption"
      style={{
        fontSize: 11,
        fontWeight: 700,
        letterSpacing: '0.08em',
        textTransform: 'uppercase',
        color: light ? 'rgba(255,255,255,0.6)' : T.accent,
        marginBottom: 'var(--s)',
        display: 'block',
      }}
    >
      {children}
    </Typography>
  )
}

function CardTitle({ children, size }: { children: React.ReactNode; size?: number }) {
  return (
    <Typography
      variant="h5"
      color="white"
      style={{ fontSize: size ?? 20, fontWeight: 700, letterSpacing: '-0.02em', lineHeight: 1.25 }}
    >
      {children}
    </Typography>
  )
}

function CardBody({ children }: { children: React.ReactNode }) {
  return (
    <Typography
      variant="textSm"
      style={{ color: '#777777', lineHeight: 1.6, marginTop: 'var(--s)', display: 'block' }}
    >
      {children}
    </Typography>
  )
}

function CardIcon({ name }: { name: string }) {
  return (
    <Icon
      name={name}
      weight="solid"
      aria-hidden="true"
      style={{
        position: 'absolute', bottom: 'var(--xxl)', right: 'var(--xxl)',
        fontSize: 42, opacity: 0.08, color: '#fff', lineHeight: 1,
      }}
    />
  )
}

function CardCta({ children }: { children: React.ReactNode }) {
  return (
    <a href="https://trusti.bg" target="_blank" rel="noopener noreferrer"
      style={{ display: 'inline-flex', alignItems: 'center', gap: 'var(--xs)', fontSize: 13, fontWeight: 700, color: '#FD9A54', marginTop: 'var(--l)', textDecoration: 'none' }}>
      {children}
      <Icon name="fa-arrow-right" size="xs" weight="solid" />
    </a>
  )
}

function CardPill({ children }: { children: React.ReactNode }) {
  return (
    <div style={{
      display: 'inline-flex', alignItems: 'center', gap: 6,
      fontSize: 12, fontWeight: 600, color: '#FD9A54',
      background: 'rgba(247,104,3,0.12)', border: '1px solid rgba(247,104,3,0.2)',
      borderRadius: 99, padding: '4px 12px', marginBottom: 'var(--l)',
    }}>
      <Icon name="fa-star" size="xs" weight="solid" style={{ color: '#FD9A54' }} />
      {children}
    </div>
  )
}

function NotifyRow({ children }: { children: React.ReactNode }) {
  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 'var(--m)',
      background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.13)',
      borderRadius: 10, padding: 'var(--m) var(--l)', marginTop: 'var(--l)',
    }}>
      <span style={{
        width: 8, height: 8, borderRadius: 99, background: '#34d399', flexShrink: 0,
        boxShadow: '0 0 8px rgba(52,211,153,0.6)',
      }} />
      <Typography variant="textSm" style={{ color: '#e0e0e0' }}>
        {children}
      </Typography>
    </div>
  )
}

